func (m *CooccurrenceMatrix) Build() (map[[2]string]float64, error) {
	raw := make(map[[2]string]int)
	entityDF := make(map[string]int)

	for _, chunkID := range m.index.ChunkIDs() {
		entitiesInChunk, err := m.index.GetEntitiesForChunk(chunkID)
		if err != nil {
			return nil, fmt.Errorf("get entities for chunk %s: %w", chunkID, err)
		}
		var eids []string
		for _, pair := range entitiesInChunk {
			eids = append(eids, pair.EntityID)
			entityDF[pair.EntityID]++
		}
		for i := 0; i < len(eids); i++ {
			for j := i + 1; j < len(eids); j++ {
				a, b := eids[i], eids[j]
				if a > b {
					a, b = b, a
				}
				raw[[2]string{a, b}]++
			}
		}
	}

	total := m.index.TotalChunks()
	if total < 1 {
		total = 1
	}

	result := make(map[[2]string]float64)
	for pair, count := range raw {
		if count < m.minCooccurrence {
			continue
		}
		dfA := entityDF[pair[0]]
		if dfA == 0 {
			dfA = 1
		}
		dfB := entityDF[pair[1]]
		if dfB == 0 {
			dfB = 1
		}
		score, err := m.normalise(count, dfA, dfB, total)
		if err != nil {
			return nil, err
		}
		result[pair] = score
	}
	return result, nil
}

