type CooccurrenceMatrix struct {
	index           *EntityIndex
	normalization   string
	minCooccurrence int
}

type CooccurrenceOptions struct {
	Normalization   string
	MinCooccurrence int
}

func NewCooccurrenceMatrix(index *EntityIndex, opts CooccurrenceOptions) *CooccurrenceMatrix {
	if opts.Normalization == "" {
		opts.Normalization = "pmi"
	}
	if opts.MinCooccurrence == 0 {
		opts.MinCooccurrence = 2
	}
	return &CooccurrenceMatrix{
		index:           index,
		normalization:   opts.Normalization,
		minCooccurrence: opts.MinCooccurrence,
	}
}

func (m *CooccurrenceMatrix) Build() (map[[2]string]float64, error) {
	raw := make(map[[2]string]int)
	entityDF := make(map[string]int)
	for _, chunkID := range m.index.ChunkIDs() {
		pairs, err := m.index.GetEntitiesForChunk(chunkID)
		if err != nil {
			return nil, fmt.Errorf("entities for chunk %s: %w", chunkID, err)
		}
		var eids []string
		for _, p := range pairs {
			eids = append(eids, p.EntityID)
			entityDF[p.EntityID]++
		}
		for i := 0; i < len(eids); i++ {
			for j := i + 1; j < len(eids); j++ {
				a, b := eids[i], eids[j]
				if a > b { a, b = b, a }
				raw[[2]string{a, b}]++
			}
		}
	}
	total := m.index.TotalChunks()
	if total < 1 {
		total = 1
	}
	result := make(map[[2]string]float64)
	for pair, count := range raw {
		if count < m.minCooccurrence {
			continue
		}
		dfA, dfB := entityDF[pair[0]], entityDF[pair[1]]
		if dfA == 0 { dfA = 1 }
		if dfB == 0 { dfB = 1 }
		score, err := m.normalise(count, dfA, dfB, total)
		if err != nil {
			return nil, err
		}
		result[pair] = score
	}
	return result, nil
}

func clusterEntities(
	cooccurrence map[[2]string]float64,
	entities []string,
	algorithm string,
	distanceThreshold float64,
) (map[string]string, error) {
	if len(entities) == 0 {
		return nil, nil
	}
	switch algorithm {
	case "agglomerative":
		return agglomerative(cooccurrence, entities, distanceThreshold)
	case "dbscan":
		return dbscan(cooccurrence, entities, distanceThreshold)
	case "leiden":
		return leiden(cooccurrence, entities, distanceThreshold)
	}
	return nil, fmt.Errorf("unknown clustering algorithm: %q", algorithm)
}
